// Prepara cada email pendiente con el prompt AI y referencia de alojamientos
const emails = $input.all();
const alojNode = $('GetAlojamientos').first();

// Si no hay emails, terminamos
if (emails.length === 0 || !emails[0] || !emails[0].json || !emails[0].json.id) {
  return [{ json: { _empty: true } }];
}

// Construir referencia de alojamientos
let alojText = '';
if (alojNode && alojNode.json) {
  const rowsObj = alojNode.json;
  // Puede venir como array directo o como objeto con rows
  const rows = Array.isArray(rowsObj) ? rowsObj : (rowsObj.rows || []);
  alojText = rows.map(a => {
    const id = a.AlojamientoStayslistingIdLargo || a.AlojamientoStayslistingId || 'N/A';
    const num = a.AlojamientoNumero || '?';
    const name = a.AlojamientoStaysInternalName || a.AlojamientoNombre || '';
    return `  ID:${id} | Depto:${num} | ${name}`;
  }).join('\n');
}

return emails.map(e => {
  const raw = e.json.payload_raw;
  let emailText = '';
  let subject = e.json.subject || '';

  try {
    if (typeof raw === 'string') {
      const parsed = JSON.parse(raw);
      emailText = parsed.cuerpo_texto || parsed.cuerpo_html || parsed.text || raw;
      subject = parsed.asunto || parsed.subject || subject;
    } else if (typeof raw === 'object' && raw !== null) {
      emailText = raw.cuerpo_texto || raw.cuerpo_html || raw.text || JSON.stringify(raw);
      subject = raw.asunto || raw.subject || subject;
    } else {
      emailText = String(raw);
    }
  } catch(err) {
    emailText = String(raw);
  }

  const prompt = `Eres un asistente que procesa correos de Airbnb. Analiza el siguiente correo y devuelve SOLO un JSON valido (sin markdown, sin explicaciones):

ASUNTO: ${subject}
TEXTO: ${emailText.substring(0, 3000)}

ALOJAMIENTOS DISPONIBLES (ID externo Stays, Numero interno, Nombre):
${alojText}

Devuelve EXACTAMENTE este JSON, nada mas:
{"es_mensaje":true,"es_alerta":false,"motivo_alerta":"","nombre_remitente":"Maria Perez","texto_mensaje":"Hola, queria saber...","fecha_mensaje":"2026-06-07 14:30","idalojamiento":"698ead2e065bcaac0d2f4940","numero_alojamiento":901}

REGLAS:
- es_mensaje: false si es publicidad, notificacion de reserva automatica, confirmacion, factura, ruido. true si es un mensaje real de un huesped o de Valentina.
- es_alerta: true SOLO si contiene reclamo, queja, emergencia, urgencia, reserva de ultima hora (menos de 24h), problema grave.
- idalojamiento: busca en la lista de arriba el ID que coincida con el numero de departamento mencionado. Si no puedes determinarlo, usa null.
- nombre_remitente: extrae el nombre de quien escribe (puede ser huesped o Valentina).
- fecha_mensaje: extrae la fecha si aparece. Formato YYYY-MM-DD HH:MM.
- texto_mensaje: el texto limpio del mensaje, sin firmas ni headers.`;

  return {
    json: {
      bandeja_id: e.json.id,
      from_email: e.json.from_email,
      subject: subject,
      email_text: emailText,
      ai_prompt: prompt
    }
  };
});

// Parsea la respuesta JSON de OpenAI API y extrae los campos
// Recupera bandeja_id del nodo PreparePrompt (mismo orden de items)
const items = $input.all();
const promptItems = $('PreparePrompt').all();

return items.map((item, index) => {
  const rawResponse = item.json.choices?.[0]?.message?.content || '';
  const bandejaId = promptItems[index]?.json?.bandeja_id;

  let parsed = {};
  try {
    let content = rawResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    parsed = JSON.parse(content);
  } catch(e) {
    parsed = {
      es_mensaje: false, es_alerta: false, motivo_alerta: '',
      nombre_remitente: null, texto_mensaje: null,
      fecha_mensaje: null, idalojamiento: null, numero_alojamiento: null
    };
  }

  const esMensaje = parsed.es_mensaje === true;
  const esAlerta = parsed.es_alerta === true;
  const estadoBandeja = esMensaje ? 'Procesado' : 'Descartado';

  return {
    json: {
      bandeja_id: bandejaId,
      nombre_remitente: parsed.nombre_remitente || null,
      texto_mensaje: parsed.texto_mensaje || null,
      fecha_mensaje: parsed.fecha_mensaje || null,
      idalojamiento: parsed.idalojamiento || null,
      es_alerta: esAlerta,
      alerta_procesada: !esAlerta,
      motivo_alerta: parsed.motivo_alerta || '',
      ai_response_raw: rawResponse,
      estado_bandeja: estadoBandeja
    }
  };
});
